'use strict';
var valid = true;
const errorMessage = "Please!!! Enter a number between 1 - 10";
while (valid) {
    var num = prompt('Enter the username');
    if (num === null || num.trim() === '') {
        console.log("Input canceled");
        continue;
    }
    var username = parseInt(num);
    // Is Humber
    if (!isNaN(username)) {
        if (username >= 1 && username <= 10) {
            valid = false
            console.log("The correct user")
            break;
        } else {
            alert(errorMessage)
        }
    } else {
        alert(errorMessage)

    }


}
